--
-- Table structure for table `mahasiswa`
--

DROP TABLE IF EXISTS `mahasiswa`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mahasiswa` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `nim` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nama` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `no_hp` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `alamat` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `prodi_id` bigint unsigned NOT NULL DEFAULT '1',
  `peminatan_id` bigint unsigned DEFAULT NULL,
  `semester` tinyint unsigned NOT NULL DEFAULT '1',
  `ipk` decimal(3,2) DEFAULT '0.00',
  `dosen_pa` bigint unsigned DEFAULT NULL,
  `pembimbing_1` bigint unsigned DEFAULT NULL,
  `pembimbing_2` bigint unsigned DEFAULT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'aktif',
  `angkatan` varchar(4) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `mahasiswa_nim_unique` (`nim`),
  KEY `mahasiswa_prodi_id_foreign` (`prodi_id`),
  KEY `mahasiswa_peminatan_id_foreign` (`peminatan_id`),
  KEY `mahasiswa_pembimbing_1_foreign` (`pembimbing_1`),
  KEY `mahasiswa_pembimbing_2_foreign` (`pembimbing_2`),
  KEY `mahasiswa_user_id_foreign` (`user_id`),
  CONSTRAINT `mahasiswa_pembimbing_1_foreign` FOREIGN KEY (`pembimbing_1`) REFERENCES `dosen` (`id`) ON DELETE SET NULL,
  CONSTRAINT `mahasiswa_pembimbing_2_foreign` FOREIGN KEY (`pembimbing_2`) REFERENCES `dosen` (`id`) ON DELETE SET NULL,
  CONSTRAINT `mahasiswa_peminatan_id_foreign` FOREIGN KEY (`peminatan_id`) REFERENCES `peminatan` (`id`) ON DELETE SET NULL,
  CONSTRAINT `mahasiswa_prodi_id_foreign` FOREIGN KEY (`prodi_id`) REFERENCES `prodi` (`id`) ON DELETE CASCADE,
  CONSTRAINT `mahasiswa_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1580 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `mahasiswa`
--

LOCK TABLES `mahasiswa` WRITE;
/*!40000 ALTER TABLE `mahasiswa` DISABLE KEYS */;
